#include <bits/stdc++.h>
using namespace std;
const int maxn=10;
int n;
char s[maxn][maxn];
bool aline[maxn],bline[maxn],cline[maxn];
string r,c;
void dfs(int hang) {
	if(hang>n) {
		for(int i=1; i<=n; i++) {
			for(int j=1; j<=n; j++) {
				if(s[i][j]!='.') {
					if(s[i][j]==r[i]) break;
					else return ;
				}
			}
		}
		for(int i=1; i<=n; i++) {
			for(int j=1; j<=n; j++) {
				if(s[j][i]!='.') {
					if(s[j][i]==c[i]) break;
					else return ;
				}
			}
		}
		cout<<"Yes\n";
		for(int i=1; i<=n; i++,cout<<"\n") {
			for(int j=1;j<=n;j++){
				cout<<s[i][j];
			}
		}
		exit(0);
	}
	for(int a=1;a<=n;a++){
		for(int b=1;b<=n;b++){
			if(a==b) continue;
			for(int c=1;c<=n;c++){
				if(a==c||b==c) continue;
				if(!aline[a]&&!bline[b]&&!cline[c]) {	
					s[hang][a]='A',s[hang][b]='B',s[hang][c]='C';
					aline[a]=bline[b]=cline[c]=1;
					dfs(hang+1);
					s[hang][a]=s[hang][b]=s[hang][c]='.';
					aline[a]=bline[b]=cline[c]=0;
				}
			}
		}
	}
}
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>r>>c;
	r=" "+r,c=" "+c;
	fill(s[0],s[n+1],'.');
	dfs(1);
	cout<<"No";
	return 0;
}
